#include <stdio.h>
#include <string.h>

struct Employee {
    int emp_id;
    char name[50];
    char department[30];
    float salary;
};

void displayEmployee(struct Employee e) {
    printf("%d\t%-15s\t%-10s\t%.2f\n", 
           e.emp_id, e.name, e.department, e.salary);
}

void sortBySalary(struct Employee emp[], int n) {
    struct Employee temp;
    for(int i=0; i<n-1; i++) {
        for(int j=0; j<n-i-1; j++) {
            if(emp[j].salary > emp[j+1].salary) {
                temp = emp[j];
                emp[j] = emp[j+1];
                emp[j+1] = temp;
            }
        }
    }
}

int main() {
    struct Employee staff[5] = {
        {101, "John", "IT", 50000},
        {102, "Sarah", "HR", 45000},
        {103, "Mike", "Finance", 55000},
        {104, "Emma", "IT", 48000},
        {105, "Tom", "Marketing", 42000}
    };

    int n = 5;

    printf("Before Sorting by Salary:\n");
    printf("ID\tName\t\tDepartment\tSalary\n");
    for(int i=0; i<n; i++) displayEmployee(staff[i]);

    sortBySalary(staff, n);

    printf("\nAfter Sorting by Salary:\n");
    printf("ID\tName\t\tDepartment\tSalary\n");
    for(int i=0; i<n; i++) displayEmployee(staff[i]);

    return 0;
}

class Student {
    int rollNo;
    String name;
    double marks;

    // Constructor
    Student(int rollNo, String name, double marks) {
        this.rollNo = rollNo;
        this.name = name;
        this.marks = marks;
    }

    void display() {
        System.out.println(rollNo + "\t" + name + "\t" + marks);
    }
}

public class StudentDatabase {
    public static void main(String[] args) {
        // Array of structures equivalent - array of objects
        Student[] students = new Student[3];
        students[0] = new Student(101, "Alice", 85.5);
        students[1] = new Student(102, "Bob", 92.0);
        students[2] = new Student(103, "Charlie", 78.5);

        // Display all students
        System.out.println("RollNo\tName\tMarks");
        for(int i = 0; i < students.length; i++) {
            students[i].display();
        }

        // Search by roll number
        int searchRoll = 102;
        boolean found = false;

        for(int i = 0; i < students.length; i++) {
            if(students[i].rollNo == searchRoll) {
                System.out.println("\nFound: " + students[i].name);
                found = true;
                break;
            }
        }

        if(!found) {
            System.out.println("Student not found");
        }
    }
}
